import hashlib
import os
import json
import getpass

# Define a function to check if a given username is already taken
def is_username_taken(username):
    return username in users

# Define a function to hash a password using SHA-256 algorithm
def hash_password(password):
    return hashlib.sha256(password.encode()).hexdigest()

# Define a function to check if a given password matches the stored hash value
def verify_password(username, password, stored_hash):
    return hash_password(password) == stored_hash

# Define a function to check if a given password is valid (too short or invalid characters)
def is_password_valid(password):
    return len(password) >= 8 and password.isalnum()

# Define the main function to store user data in a dictionary and persist it to a file
def store_user_data(username, password, data_file):
    user_data = {
        "username": username,
        "password": hash_password(password)
    }
    with open(data_file, "a") as file:
        json.dump(user_data, file)
        file.write("\n")

# Define a function to validate user input
def validate_input(username, password):
    if is_username_taken(username):
        return "Username already taken."
    if not is_password_valid(password):
        return "Password must be at least 8 characters long and contain only alphanumeric characters."
    return None

# Initialize a dictionary to store user data
users = {}

# Define the main function to store user data in a dictionary and persist it to a file
def main():
    global users
    data_file = "users.txt"
    while True:
        username = input("Enter a username (or 'exit' to quit): ")
        if username.lower() == "exit":
            break
        password = getpass promt("Enter a password: ")
        error_message = validate_input(username, password)
        if error_message:
            print(error_message)
        else:
            store_user_data(username, password, data_file)
            users[username] = hash_password(password)
            print("Username and password stored successfully.")

    # Persist user data to the file when the program exits
    with open(data_file, "w") as file:
        for user in users:
            user_data = {
                "username": user,
                "password": hash_password(users[user])
            }
            json.dump(user_data, file)
            file.write("\n")

if __name__ == "__main__":
    main()
